//! `vm-serve` — boot a VM and serve its live console over a WebSocket.
//!
//! This is the duplex transport that lets a Mac-hosted VM (Virtualization.framework
//! microVM, booted by `boot-iso`) be driven from a browser or a mobile app
//! (aeon-shell / aeon-forge) — the thing x-gnosis (an HTTP server) cannot do.
//!
//! The VM boots as a child process whose stdout/stderr ARE the guest serial
//! console and whose stdin feeds keystrokes back. We fan the console out to every
//! connected WebSocket client (binary frames) and merge their input back into the
//! guest. A bounded scrollback buffer is replayed to each new client so it sees
//! the boot, not just whatever streams after it connects.

use anyhow::{anyhow, Result};
use futures::{SinkExt, StreamExt};
use std::sync::Arc;
use tokio::io::{AsyncRead, AsyncReadExt, AsyncWriteExt};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::{broadcast, mpsc, Mutex};
use tokio_tungstenite::tungstenite::Message;

const SCROLLBACK_CAP: usize = 256 * 1024;

/// The browser console page: xterm.js over a WebSocket back to this same port.
/// Open `http://127.0.0.1:<port>/` in any browser (or an aeon-shell / aeon-forge
/// webview) to see and drive the live VM.
const CONSOLE_HTML: &str = r#"<!doctype html><html><head><meta charset="utf-8">
<title>vCPU console</title>
<link rel="stylesheet" href="https://unpkg.com/@xterm/xterm/css/xterm.css">
<style>html,body{margin:0;height:100%;background:#000}#t{height:100vh;width:100vw}</style>
</head><body><div id="t"></div>
<script src="https://unpkg.com/@xterm/xterm/lib/xterm.js"></script>
<script src="https://unpkg.com/@xterm/addon-fit/lib/addon-fit.js"></script>
<script>
const term=new Terminal({cursorBlink:true,fontFamily:'Menlo,monospace',fontSize:13,theme:{background:'#000'}});
const fit=new FitAddon.FitAddon();term.loadAddon(fit);term.open(document.getElementById('t'));fit.fit();
const ws=new WebSocket((location.protocol==='https:'?'wss':'ws')+'://'+location.host+'/');
ws.binaryType='arraybuffer';
ws.onmessage=e=>term.write(new Uint8Array(e.data));
term.onData(d=>ws.send(new TextEncoder().encode(d)));
ws.onopen=()=>{term.focus();fit.fit();};
ws.onclose=()=>term.write('\r\n\x1b[31m[vm-serve: console closed]\x1b[0m\r\n');
addEventListener('resize',()=>fit.fit());
</script></body></html>"#;

/// Pump one console reader (stdout or stderr) into the scrollback + broadcast.
async fn pump_reader<R: AsyncRead + Unpin + Send + 'static>(
    mut reader: R,
    tx: broadcast::Sender<Vec<u8>>,
    scrollback: Arc<Mutex<Vec<u8>>>,
) {
    let mut buf = [0u8; 8192];
    loop {
        match reader.read(&mut buf).await {
            Ok(0) | Err(_) => break,
            Ok(n) => {
                let chunk = buf[..n].to_vec();
                {
                    let mut sb = scrollback.lock().await;
                    sb.extend_from_slice(&chunk);
                    if sb.len() > SCROLLBACK_CAP {
                        let cut = sb.len() - SCROLLBACK_CAP;
                        sb.drain(..cut);
                    }
                }
                let _ = tx.send(chunk);
            }
        }
    }
}

/// Serve a static HTML page over a plain HTTP/1.1 response.
async fn serve_http(mut stream: TcpStream, body: &str) {
    let mut scratch = [0u8; 4096];
    let _ = stream.read(&mut scratch).await; // consume the request line + headers
    let body = body.as_bytes();
    let head = format!(
        "HTTP/1.1 200 OK\r\nContent-Type: text/html; charset=utf-8\r\nContent-Length: {}\r\nConnection: close\r\n\r\n",
        body.len()
    );
    let _ = stream.write_all(head.as_bytes()).await;
    let _ = stream.write_all(body).await;
    let _ = stream.flush().await;
}

/// The Android screen page: a `<canvas>` that draws PNG frames pushed over the
/// WebSocket, and forwards taps/keys back as JSON. Pure canvas + WebSocket — works
/// in every browser including iOS Safari (no codec, no WebRTC).
const ANDROID_HTML: &str = r#"<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no">
<title>Android — vm serve</title>
<style>html,body{margin:0;height:100%;background:#111;overflow:hidden;touch-action:none}
#s{display:block;margin:0 auto;height:100vh;background:#000;touch-action:none}</style>
</head><body><canvas id="s"></canvas>
<script>
const cv=document.getElementById('s'),ctx=cv.getContext('2d');
let dw=1080,dh=2400;
const ws=new WebSocket((location.protocol==='https:'?'wss':'ws')+'://'+location.host+'/');
ws.binaryType='arraybuffer';
ws.onmessage=async e=>{const bmp=await createImageBitmap(new Blob([e.data],{type:'image/png'}));
  dw=bmp.width;dh=bmp.height;const ar=dw/dh,h=window.innerHeight,w=h*ar;cv.width=w;cv.height=h;
  ctx.drawImage(bmp,0,0,w,h);bmp.close&&bmp.close();};
function pt(ev){const r=cv.getBoundingClientRect();const cx=(ev.touches?ev.touches[0].clientX:ev.clientX)-r.left;
  const cy=(ev.touches?ev.touches[0].clientY:ev.clientY)-r.top;
  return {x:Math.round(cx/r.width*dw),y:Math.round(cy/r.height*dh)};}
let down=null;
cv.addEventListener('pointerdown',ev=>{down=pt(ev);ev.preventDefault();});
cv.addEventListener('pointerup',ev=>{const u=pt(ev);if(down){const dx=u.x-down.x,dy=u.y-down.y;
  if(Math.abs(dx)+Math.abs(dy)<24)ws.send(JSON.stringify({t:'tap',x:u.x,y:u.y}));
  else ws.send(JSON.stringify({t:'swipe',x:down.x,y:down.y,x2:u.x,y2:u.y}));}down=null;ev.preventDefault();});
addEventListener('keydown',ev=>{ws.send(JSON.stringify({t:'keyev',k:ev.key}));ev.preventDefault();});
ws.onopen=()=>cv.focus();
</script></body></html>"#;

/// Best-effort LAN IPv4 (so a phone / another device can reach a `--lan` serve).
fn lan_ip() -> Option<String> {
    for iface in ["en0", "en1", "en2"] {
        if let Ok(o) = std::process::Command::new("ipconfig")
            .args(["getifaddr", iface])
            .output()
        {
            let ip = String::from_utf8_lossy(&o.stdout).trim().to_string();
            if !ip.is_empty() {
                return Some(ip);
            }
        }
    }
    None
}

/// Boot `target` (a path, an `http(s)://` ISO URL, or an `aeon://iso/<id>` the
/// caller already resolved) and serve its console on `<host>:<port>` — an HTTP
/// xterm.js page + a WebSocket on the same port. `host` is `127.0.0.1` (local) or
/// `0.0.0.0` (LAN/mobile). Runs until the VM exits or the process is stopped.
pub async fn serve(target: &str, host: &str, port: u16) -> Result<()> {
    // `boot-iso` sets SWERVE_VZ_BRIDGE, downloads URL ISOs, and boots — its
    // stdout is the live guest console. Pipe the console instead of inheriting it.
    let mut child = tokio::process::Command::new("boot-iso")
        .arg(target)
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .spawn()
        .map_err(|e| anyhow!("spawn boot-iso (is it on PATH?): {e}"))?;

    let cstdout = child.stdout.take().ok_or_else(|| anyhow!("no child stdout"))?;
    let cstderr = child.stderr.take().ok_or_else(|| anyhow!("no child stderr"))?;
    let mut cstdin = child.stdin.take().ok_or_else(|| anyhow!("no child stdin"))?;

    let (out_tx, _) = broadcast::channel::<Vec<u8>>(2048);
    let (in_tx, mut in_rx) = mpsc::channel::<Vec<u8>>(256);
    let scrollback: Arc<Mutex<Vec<u8>>> = Arc::new(Mutex::new(Vec::new()));

    tokio::spawn(pump_reader(cstdout, out_tx.clone(), scrollback.clone()));
    tokio::spawn(pump_reader(cstderr, out_tx.clone(), scrollback.clone()));

    // Merged client input → guest stdin.
    tokio::spawn(async move {
        while let Some(bytes) = in_rx.recv().await {
            if cstdin.write_all(&bytes).await.is_err() {
                break;
            }
            let _ = cstdin.flush().await;
        }
    });

    let listener = TcpListener::bind((host, port)).await?;
    let shown = if host == "0.0.0.0" {
        lan_ip().unwrap_or_else(|| "<this-host-ip>".to_string())
    } else {
        host.to_string()
    };
    eprintln!("vm-serve: open http://{shown}:{port}/ in a browser (ws on the same port) — Ctrl-C to stop");
    if host == "0.0.0.0" {
        eprintln!("vm-serve: reachable on your LAN (phone / another device) at the URL above");
    }

    loop {
        let (stream, _peer) = listener.accept().await?;
        let mut out_rx = out_tx.subscribe();
        let in_tx = in_tx.clone();
        let sb = scrollback.clone();
        tokio::spawn(async move {
            // Peek (without consuming) to route one port: a WebSocket upgrade goes
            // to the console transport; anything else gets the xterm HTML page.
            let mut peek = [0u8; 1024];
            let n = match stream.peek(&mut peek).await {
                Ok(n) => n,
                Err(_) => return,
            };
            if !String::from_utf8_lossy(&peek[..n])
                .to_ascii_lowercase()
                .contains("upgrade: websocket")
            {
                serve_http(stream, CONSOLE_HTML).await;
                return;
            }
            let ws = match tokio_tungstenite::accept_async(stream).await {
                Ok(w) => w,
                Err(_) => return,
            };
            let (mut sink, mut src) = ws.split();
            // Replay scrollback so a fresh client sees the boot, then go live.
            let snapshot = sb.lock().await.clone();
            if !snapshot.is_empty() && sink.send(Message::Binary(snapshot)).await.is_err() {
                return;
            }
            let send = tokio::spawn(async move {
                while let Ok(chunk) = out_rx.recv().await {
                    if sink.send(Message::Binary(chunk)).await.is_err() {
                        break;
                    }
                }
            });
            while let Some(Ok(msg)) = src.next().await {
                let data = match msg {
                    Message::Binary(b) => b,
                    Message::Text(t) => t.into_bytes(),
                    Message::Close(_) => break,
                    _ => continue,
                };
                if in_tx.send(data).await.is_err() {
                    break;
                }
            }
            send.abort();
        });
    }
}

/// Resolve the `adb` binary (ANDROID_HOME/SDK, else PATH).
fn adb_bin() -> String {
    for var in ["ANDROID_HOME", "ANDROID_SDK_ROOT"] {
        if let Ok(home) = std::env::var(var) {
            let p = format!("{home}/platform-tools/adb");
            if std::path::Path::new(&p).is_file() {
                return p;
            }
        }
    }
    if let Ok(home) = std::env::var("HOME") {
        let p = format!("{home}/Library/Android/sdk/platform-tools/adb");
        if std::path::Path::new(&p).is_file() {
            return p;
        }
    }
    "adb".to_string()
}

/// Map a JSON input event from the browser to `adb shell input` args.
fn adb_input_args(json: &str, device: &str) -> Option<Vec<String>> {
    let get = |k: &str| -> Option<String> {
        let pat = format!("\"{k}\":");
        let i = json.find(&pat)? + pat.len();
        let rest = json[i..].trim_start();
        if let Some(r) = rest.strip_prefix('"') {
            Some(r[..r.find('"')?].to_string())
        } else {
            let end = rest.find([',', '}'])?;
            Some(rest[..end].trim().to_string())
        }
    };
    let t = get("t")?;
    let mut a = vec!["-s".into(), device.into(), "shell".into(), "input".into()];
    match t.as_str() {
        "tap" => {
            a.push("tap".into());
            a.push(get("x")?);
            a.push(get("y")?);
        }
        "swipe" => {
            a.push("swipe".into());
            a.push(get("x")?);
            a.push(get("y")?);
            a.push(get("x2")?);
            a.push(get("y2")?);
            a.push("80".into());
        }
        "keyev" => {
            let k = get("k")?;
            let code = match k.as_str() {
                "Enter" => "KEYCODE_ENTER",
                "Backspace" => "KEYCODE_DEL",
                "ArrowUp" => "KEYCODE_DPAD_UP",
                "ArrowDown" => "KEYCODE_DPAD_DOWN",
                "ArrowLeft" => "KEYCODE_DPAD_LEFT",
                "ArrowRight" => "KEYCODE_DPAD_RIGHT",
                " " => "KEYCODE_SPACE",
                _ if k.chars().count() == 1 => {
                    a.push("text".into());
                    a.push(k);
                    return Some(a);
                }
                _ => return None,
            };
            a.push("keyevent".into());
            a.push(code.into());
        }
        _ => return None,
    }
    Some(a)
}

/// Stream an Android device/emulator's SCREEN to a `<canvas>` over WebSocket
/// (`adb exec-out screencap -p` frames out, taps/keys back). Works on iOS Safari.
///
/// # Errors
/// Reports a bind failure.
pub async fn serve_screen(device: &str, host: &str, port: u16) -> Result<()> {
    let adb = adb_bin();
    let _ = std::process::Command::new(&adb)
        .args(["-s", device, "wait-for-device"])
        .status();

    let (out_tx, _) = broadcast::channel::<Vec<u8>>(8);
    let (in_tx, mut in_rx) = mpsc::channel::<String>(256);

    // Frame producer: a screencap loop with a per-frame timeout so a busy adbd
    // drops a frame instead of wedging the stream.
    {
        let (adb, dev, tx) = (adb.clone(), device.to_string(), out_tx.clone());
        tokio::spawn(async move {
            loop {
                let fut = tokio::process::Command::new(&adb)
                    .args(["-s", &dev, "exec-out", "screencap", "-p"])
                    .output();
                if let Ok(Ok(o)) =
                    tokio::time::timeout(std::time::Duration::from_secs(4), fut).await
                {
                    if o.status.success() && o.stdout.starts_with(b"\x89PNG") {
                        let _ = tx.send(o.stdout);
                    }
                }
                tokio::time::sleep(std::time::Duration::from_millis(220)).await;
            }
        });
    }
    // Input consumer: browser JSON events → adb shell input.
    {
        let (adb, dev) = (adb.clone(), device.to_string());
        tokio::spawn(async move {
            while let Some(json) = in_rx.recv().await {
                if let Some(args) = adb_input_args(&json, &dev) {
                    let _ = tokio::process::Command::new(&adb).args(&args).output().await;
                }
            }
        });
    }

    let listener = TcpListener::bind((host, port)).await?;
    let shown = if host == "0.0.0.0" {
        lan_ip().unwrap_or_else(|| "<this-host-ip>".into())
    } else {
        host.to_string()
    };
    eprintln!("vm screen: open http://{shown}:{port}/ — live Android ({device}) in any browser (incl. iOS)");

    loop {
        let (stream, _peer) = listener.accept().await?;
        let mut out_rx = out_tx.subscribe();
        let in_tx = in_tx.clone();
        tokio::spawn(async move {
            let mut peek = [0u8; 1024];
            let n = match stream.peek(&mut peek).await {
                Ok(n) => n,
                Err(_) => return,
            };
            if !String::from_utf8_lossy(&peek[..n])
                .to_ascii_lowercase()
                .contains("upgrade: websocket")
            {
                serve_http(stream, ANDROID_HTML).await;
                return;
            }
            let ws = match tokio_tungstenite::accept_async(stream).await {
                Ok(w) => w,
                Err(_) => return,
            };
            let (mut sink, mut src) = ws.split();
            let send = tokio::spawn(async move {
                while let Ok(frame) = out_rx.recv().await {
                    if sink.send(Message::Binary(frame)).await.is_err() {
                        break;
                    }
                }
            });
            while let Some(Ok(msg)) = src.next().await {
                match msg {
                    Message::Text(t) => {
                        if in_tx.send(t).await.is_err() {
                            break;
                        }
                    }
                    Message::Close(_) => break,
                    _ => {}
                }
            }
            send.abort();
        });
    }
}
